import os
import torch
import numpy as np
from torch import nn, optim
from torch.utils.data import Dataset, DataLoader, random_split

# Setup working directory
working_dir = os.path.join(os.getcwd(), "working")
os.makedirs(working_dir, exist_ok=True)

# Device configuration
device = torch.device("cuda" if torch.cuda.is_available() else "cpu")


# Define synthetic dataset
class CosmologyDataset(Dataset):
    def __init__(self, size=1000):
        self.data = np.random.uniform(0, 2, (size, 1))  # Simulated redshifts
        self.targets = np.sin(self.data) + 0.1 * np.random.randn(size, 1)

    def __len__(self):
        return len(self.data)

    def __getitem__(self, index):
        return torch.FloatTensor(self.data[index]), torch.FloatTensor(
            self.targets[index]
        )


# Create dataset and split into train/val
dataset = CosmologyDataset()
train_size = int(0.8 * len(dataset))
val_size = len(dataset) - train_size
train_dataset, val_dataset = random_split(dataset, [train_size, val_size])

train_loader = DataLoader(train_dataset, batch_size=32, shuffle=True)
val_loader = DataLoader(val_dataset, batch_size=32)


# Define a simple neural network model with configurable initialization
class SimpleModel(nn.Module):
    def __init__(self, init_method=None):
        super(SimpleModel, self).__init__()
        self.fc = nn.Sequential(
            nn.Linear(1, 64), nn.ReLU(), nn.Linear(64, 64), nn.ReLU(), nn.Linear(64, 1)
        )
        if init_method:
            self._initialize_weights(init_method)

    def forward(self, x):
        return self.fc(x)

    def _initialize_weights(self, init_method):
        for layer in self.fc:
            if isinstance(layer, nn.Linear):
                if init_method == "xavier":
                    nn.init.xavier_uniform_(layer.weight)
                elif init_method == "he":
                    nn.init.kaiming_uniform_(layer.weight, nonlinearity="relu")


# Define hyperparameter tuning experiments
init_methods = ["default", "xavier", "he"]
experiment_data = {
    f"init_{method}": {
        "synthetic_cosmology": {
            "metrics": {"train": [], "val": []},
            "losses": {"train": [], "val": []},
            "predictions": [],
            "ground_truth": [],
        }
    }
    for method in init_methods
}

num_epochs = 20

# Training loop with different initialization methods
for init_method in init_methods:
    model = SimpleModel(
        init_method=(init_method if init_method != "default" else None)
    ).to(device)
    criterion = nn.MSELoss()
    optimizer = optim.Adam(model.parameters(), lr=0.001)

    for epoch in range(num_epochs):
        model.train()
        training_loss = 0.0
        for batch in train_loader:
            inputs, targets = batch
            inputs, targets = inputs.to(device), targets.to(device)

            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, targets)
            loss.backward()
            optimizer.step()

            training_loss += loss.item()

        experiment_data[f"init_{init_method}"]["synthetic_cosmology"]["losses"][
            "train"
        ].append(training_loss / len(train_loader))

        # Validation
        model.eval()
        val_loss = 0.0
        with torch.no_grad():
            for batch in val_loader:
                inputs, targets = batch
                inputs, targets = inputs.to(device), targets.to(device)
                outputs = model(inputs)
                loss = criterion(outputs, targets)
                val_loss += loss.item()

                # Save predictions and ground truth
                experiment_data[f"init_{init_method}"]["synthetic_cosmology"][
                    "predictions"
                ].extend(outputs.cpu().numpy())
                experiment_data[f"init_{init_method}"]["synthetic_cosmology"][
                    "ground_truth"
                ].extend(targets.cpu().numpy())

        val_loss /= len(val_loader)
        experiment_data[f"init_{init_method}"]["synthetic_cosmology"]["losses"][
            "val"
        ].append(val_loss)

        # Simplified Bayesian Evidence Ratio placeholder
        BER = np.exp(-val_loss)
        experiment_data[f"init_{init_method}"]["synthetic_cosmology"]["metrics"][
            "val"
        ].append(BER)

        print(
            f"Init {init_method.capitalize()} - Epoch {epoch + 1}: validation_loss = {val_loss:.4f}, BER = {BER:.4f}"
        )

# Save experiment data
np.save(os.path.join(working_dir, "experiment_data.npy"), experiment_data)

import os
import torch
import numpy as np
from torch import nn, optim
from torch.utils.data import Dataset, DataLoader, random_split
import matplotlib.pyplot as plt

# Setup working directory
working_dir = os.path.join(os.getcwd(), "working")
os.makedirs(working_dir, exist_ok=True)

# Device configuration
device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
print(f"Using device: {device}")


# Define synthetic dataset
class CosmologyDataset(Dataset):
    def __init__(self, size=1000):
        self.data = np.random.uniform(0, 2, (size, 1))  # Simulated redshifts
        self.targets = np.sin(self.data) + 0.1 * np.random.randn(size, 1)

    def __len__(self):
        return len(self.data)

    def __getitem__(self, index):
        return torch.FloatTensor(self.data[index]), torch.FloatTensor(
            self.targets[index]
        )


dataset = CosmologyDataset()
train_size = int(0.8 * len(dataset))
val_size = len(dataset) - train_size
train_dataset, val_dataset = random_split(dataset, [train_size, val_size])

train_loader = DataLoader(train_dataset, batch_size=32, shuffle=True)
val_loader = DataLoader(val_dataset, batch_size=32)


class SimpleModel(nn.Module):
    def __init__(self):
        super(SimpleModel, self).__init__()
        self.fc = nn.Sequential(
            nn.Linear(1, 64), nn.ReLU(), nn.Linear(64, 64), nn.ReLU(), nn.Linear(64, 1)
        )

    def forward(self, x):
        return self.fc(x)


# Define different schedulers to iterate over
scheduler_configs = {
    "StepLR": lambda optim: optim.lr_scheduler.StepLR(optim, step_size=5, gamma=0.1),
    "ReduceLROnPlateau": lambda optim: optim.lr_scheduler.ReduceLROnPlateau(
        optim, mode="min", factor=0.5, patience=2
    ),
}

experiment_data = {
    "learning_rate_scheduler_tuning": {
        "synthetic_cosmology": {
            "StepLR": {
                "metrics": {"train": [], "val": []},
                "losses": {"train": [], "val": []},
                "predictions": [],
                "ground_truth": [],
            },
            "ReduceLROnPlateau": {
                "metrics": {"train": [], "val": []},
                "losses": {"train": [], "val": []},
                "predictions": [],
                "ground_truth": [],
            },
        }
    }
}

for scheduler_name, scheduler_fn in scheduler_configs.items():
    model = SimpleModel().to(device)
    criterion = nn.MSELoss()
    optimizer = optim.Adam(model.parameters(), lr=0.001)
    scheduler = scheduler_fn(optimizer)

    num_epochs = 20
    for epoch in range(num_epochs):
        model.train()
        training_loss = 0.0
        for inputs, targets in train_loader:
            inputs, targets = inputs.to(device), targets.to(device)

            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, targets)
            loss.backward()
            optimizer.step()

            training_loss += loss.item()

        avg_train_loss = training_loss / len(train_loader)
        experiment_data["learning_rate_scheduler_tuning"]["synthetic_cosmology"][
            scheduler_name
        ]["losses"]["train"].append(avg_train_loss)

        model.eval()
        val_loss = 0.0
        with torch.no_grad():
            for inputs, targets in val_loader:
                inputs, targets = inputs.to(device), targets.to(device)
                outputs = model(inputs)
                loss = criterion(outputs, targets)
                val_loss += loss.item()

                experiment_data["learning_rate_scheduler_tuning"][
                    "synthetic_cosmology"
                ][scheduler_name]["predictions"].extend(outputs.cpu().numpy())
                experiment_data["learning_rate_scheduler_tuning"][
                    "synthetic_cosmology"
                ][scheduler_name]["ground_truth"].extend(targets.cpu().numpy())

        avg_val_loss = val_loss / len(val_loader)
        experiment_data["learning_rate_scheduler_tuning"]["synthetic_cosmology"][
            scheduler_name
        ]["losses"]["val"].append(avg_val_loss)

        BER = np.exp(-avg_val_loss)
        experiment_data["learning_rate_scheduler_tuning"]["synthetic_cosmology"][
            scheduler_name
        ]["metrics"]["val"].append(BER)

        if scheduler_name == "ReduceLROnPlateau":
            scheduler.step(avg_val_loss)
        else:
            scheduler.step()

        print(
            f"{scheduler_name} | Epoch {epoch + 1}: validation_loss = {avg_val_loss:.4f}, BER = {BER:.4f}"
        )

np.save(os.path.join(working_dir, "experiment_data.npy"), experiment_data)
